'use client';

import type { LessonRecurrence } from '@soenglish/shared-types';
import { Button, Field } from '../../../../components/ui';
import type { SetupTabProps } from './types';
import styles from '../../../../app/calendar/page.module.scss';

export function LessonSetupTab({
  text,
  canEdit,
  role,
  form,
  students,
  teachers,
  weekDayOptions,
  onChange,
}: SetupTabProps) {
  const showTeacherField = role === 'admin' || role === 'super-admin';
  return (
    <div className={`${styles.modalFieldsGrid} ${styles.modalSetupGrid}`}>
      <div className={styles.fieldGroup}>
        <label className={styles.fieldLabel}>{text.fields.title}</label>
        <Field className={styles.fieldInput} value={form.title} disabled={!canEdit} onChange={(e) => onChange({ ...form, title: e.target.value })} />
      </div>
      <div className={styles.fieldGroup}>
        <label className={styles.fieldLabel}>{text.fields.date}</label>
        <Field type="date" className={styles.fieldInput} value={form.date} disabled={!canEdit} onChange={(e) => onChange({ ...form, date: e.target.value })} />
      </div>
      <div className={styles.fieldGroup}>
        <label className={styles.fieldLabel}>{text.fields.startTime}</label>
        <Field type="time" className={styles.fieldInput} value={form.startTime} disabled={!canEdit} onChange={(e) => onChange({ ...form, startTime: e.target.value })} />
      </div>
      <div className={styles.fieldGroup}>
        <label className={styles.fieldLabel}>{text.fields.duration}</label>
        <Field type="number" className={styles.fieldInput} min={55} step={5} value={String(form.duration)} disabled={!canEdit} onChange={(e) => onChange({ ...form, duration: Math.max(55, Number(e.target.value) || 55) })} />
      </div>
      <div className={styles.fieldGroup}>
        <label className={styles.fieldLabel}>{text.fields.recurrence}</label>
        <Field as="select" className={styles.fieldInput} value={form.recurrence} disabled={!canEdit} onChange={(e) => onChange({ ...form, recurrence: e.target.value as LessonRecurrence })}>
          <option value="none">{text.options.noRepeat}</option>
          <option value="daily">{text.options.daily}</option>
          <option value="weekly">{text.options.weekly}</option>
          <option value="monthly">{text.options.monthly}</option>
        </Field>
      </div>
      <div className={styles.fieldGroup}>
        <label className={styles.fieldLabel}>{text.fields.status}</label>
        <Field as="select" className={styles.fieldInput} value={form.status} disabled={!canEdit} onChange={(e) => onChange({ ...form, status: e.target.value as typeof form.status, cancelReason: e.target.value === 'cancelled' ? form.cancelReason : undefined })}>
          <option value="planned">{text.options.planned}</option>
          <option value="completed">{text.options.completed}</option>
          <option value="cancelled">{text.options.cancelled}</option>
        </Field>
      </div>
      {form.status === 'cancelled' ? (
        <div className={styles.fieldGroup}>
          <label className={styles.fieldLabel}>{text.fields.cancelReason}</label>
          <Field as="select" className={styles.fieldInput} value={form.cancelReason ?? 'student_absent'} disabled={!canEdit} onChange={(e) => onChange({ ...form, cancelReason: e.target.value as NonNullable<typeof form.cancelReason> })}>
            <option value="student_absent">{text.options.studentAbsent}</option>
            <option value="student_requested_cancel">{text.options.studentRequestedCancel}</option>
            <option value="teacher_absent">{text.options.teacherAbsent}</option>
          </Field>
        </div>
      ) : null}
      {form.status === 'cancelled' ? (
        <div className={styles.fieldGroup}>
          <label className={styles.fieldLabel}>{text.fields.credited}</label>
          <Field as="select" className={styles.fieldInput} value={form.credited ? 'yes' : 'no'} disabled={!canEdit} onChange={(e) => onChange({ ...form, credited: e.target.value === 'yes' })}>
            <option value="yes">{text.options.credited}</option>
            <option value="no">{text.options.notCredited}</option>
          </Field>
        </div>
      ) : null}
      {form.recurrence === 'weekly' ? (
        <div className={styles.fieldGroup}>
          <label className={styles.fieldLabel}>{text.fields.weekDays}</label>
          <div className={styles.weekDaysRow}>
            {weekDayOptions.map((day) => {
              const selected = form.weeklyDays.includes(day.value);
              return (
                <Button
                  key={day.value}
                  type="button"
                  className={`${styles.weekDayChip} ${selected ? styles.weekDayChipActive : ''}`}
                  onClick={() => {
                    const next = selected
                      ? form.weeklyDays.filter((weekday) => weekday !== day.value)
                      : [...form.weeklyDays, day.value];
                    onChange({ ...form, weeklyDays: next.sort((a, b) => a - b) });
                  }}
                >
                  {day.label}
                </Button>
              );
            })}
          </div>
        </div>
      ) : null}
      {showTeacherField ? (
        <div className={styles.fieldGroup}>
          <label className={styles.fieldLabel}>Teacher</label>
          <Field
            as="select"
            className={styles.fieldInput}
            value={form.teacherId}
            disabled={!canEdit}
            onChange={(e) => {
              const nextTeacher = teachers.find((teacher) => teacher.id === e.target.value);
              if (!nextTeacher) return;
              onChange({
                ...form,
                teacherId: nextTeacher.id,
                teacherName: nextTeacher.fullName,
              });
            }}
          >
            {teachers.map((teacher) => (
              <option key={teacher.id} value={teacher.id}>
                {teacher.fullName}
              </option>
            ))}
          </Field>
        </div>
      ) : null}
      {role !== 'student' ? (
        <div className={styles.fieldGroup}>
          <label className={styles.fieldLabel}>{text.fields.student}</label>
          <Field as="select" className={styles.fieldInput} value={form.studentId} disabled={!canEdit} onChange={(e) => {
            const nextStudent = students.find((student) => student.id === e.target.value);
            if (!nextStudent) return;
            onChange({
              ...form,
              studentId: nextStudent.id,
              studentName: nextStudent.fullName,
            });
          }}>
            {students.map((student) => (
              <option key={student.id} value={student.id}>
                {student.fullName}
              </option>
            ))}
          </Field>
        </div>
      ) : null}
    </div>
  );
}
