'use client';

import { useEffect, useMemo, useState } from 'react';
import type { ScheduledLessonDto } from '@soenglish/shared-types';
import type { UserRole } from '../../../mocks';
import { getInitialLessons } from '../services/lessonCalendarService';

export function useLessonCalendarState(activeRole: UserRole, activeStudentId: string) {
  const [lessons, setLessons] = useState<ScheduledLessonDto[]>(getInitialLessons);
  const [role, setRole] = useState<UserRole>(activeRole);
  const [view, setView] = useState<'month' | 'week'>('week');
  const [selectedDate, setSelectedDate] = useState<string | null>('2026-04-20');

  useEffect(() => {
    const autoCompletePastLessons = () => {
      const now = Date.now();
      setLessons((prev) => {
        let changed = false;
        const next: ScheduledLessonDto[] = prev.map((lesson) => {
          if (lesson.status !== 'planned') return lesson;
          const lessonEndMs = new Date(`${lesson.date}T${lesson.endTime}:00`).getTime();
          if (Number.isNaN(lessonEndMs) || lessonEndMs > now) return lesson;
          changed = true;
          return {
            ...lesson,
            status: 'completed',
            credited: true,
          };
        });
        return changed ? next : prev;
      });
    };

    autoCompletePastLessons();
    const intervalId = window.setInterval(autoCompletePastLessons, 60_000);
    return () => window.clearInterval(intervalId);
  }, []);

  const visibleLessons = useMemo(
    () => lessons.filter((lesson) => (role === 'student' ? lesson.studentId === activeStudentId : true)),
    [lessons, role, activeStudentId],
  );

  return {
    lessons,
    setLessons,
    role,
    setRole,
    view,
    setView,
    selectedDate,
    setSelectedDate,
    visibleLessons,
  };
}

